import Script from "next/script";

const BODY = "<a class=\"skip-link\" href=\"#main\">Skip to content</a>\n\n  <!-- ============ HEADER ============ -->\n  <header class=\"site-header\" id=\"top\">\n    <div class=\"container header-inner\">\n      <a class=\"brand\" href=\"#top\" aria-label=\"Sentrova home\">\n        <svg class=\"brand-mark\" width=\"30\" height=\"30\" viewBox=\"0 0 24 24\" aria-hidden=\"true\">\n          <path fill=\"var(--gold)\" d=\"M12 1 3 5v6c0 5 3.8 9.7 9 11 5.2-1.3 9-6 9-11V5z\"/>\n          <path fill=\"var(--navy)\" d=\"m10.6 14.2-2.2-2.2-1.4 1.4 3.6 3.6 6-6-1.4-1.4z\"/>\n        </svg>\n        <span class=\"brand-name\">Sentrova</span>\n      </a>\n\n      <nav class=\"primary-nav\" aria-label=\"Primary\">\n        <a href=\"#platform\">Platform</a>\n        <a href=\"#security\">Security</a>\n        <a href=\"#compliance\">Compliance</a>\n        <a href=\"#pricing\">Pricing</a>\n        <a href=\"#faq\">FAQ</a>\n      </nav>\n\n      <div class=\"header-cta\">\n        <a class=\"btn btn-ghost\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n      </div>\n\n      <button class=\"nav-toggle\" id=\"navToggle\" aria-label=\"Open menu\" aria-expanded=\"false\" aria-controls=\"mobileNav\">\n        <span></span><span></span><span></span>\n      </button>\n    </div>\n\n    <div class=\"mobile-nav\" id=\"mobileNav\" hidden>\n      <a href=\"#platform\">Platform</a>\n      <a href=\"#security\">Security</a>\n      <a href=\"#compliance\">Compliance</a>\n      <a href=\"#pricing\">Pricing</a>\n      <a href=\"#faq\">FAQ</a>\n      <a class=\"btn btn-ghost\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n    </div>\n  </header>\n\n  <main id=\"main\">\n    <!-- ============ HERO ============ -->\n    <section class=\"hero\">\n      <div class=\"container hero-grid\">\n        <div class=\"hero-copy reveal\">\n          <span class=\"eyebrow\"><span class=\"dot\"></span> The control plane for enterprise AI agents</span>\n          <p class=\"ef-line\"><span class=\"ef-badge\"><span class=\"efbox\">EF</span> Backed by Entrepreneurs First</span></p>\n          <h1>Run AI agents in production \u2014 without losing control.</h1>\n          <p class=\"lede\">\n            Sentrova is the AI gateway that sits in front of every model and agent.\n            It routes and caps spend, enforces guardrails and policies, redacts PII,\n            and logs every call as audit-ready evidence \u2014 so your security team can\n            finally say yes.\n          </p>\n          <div class=\"hero-actions\">\n            <a class=\"btn btn-primary btn-lg\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n            <a class=\"btn btn-outline btn-lg\" href=\"#how\">See how it works</a>\n          </div>\n          <div class=\"trust-strip\">\n            <span class=\"trust-label\">Built for security teams</span>\n            <div class=\"badge-row\" aria-label=\"Compliance frameworks\">\n              <span class=\"mini-badge\">SOC 2 Type II</span>\n              <span class=\"mini-badge\">ISO 27001</span>\n              <span class=\"mini-badge\">GDPR</span>\n              <span class=\"mini-badge\">HIPAA-ready</span>\n            </div>\n          </div>\n        </div>\n\n        <div class=\"hero-visual reveal\">\n          <!-- Architecture diagram: Apps -> Gateway -> Providers -->\n          <svg viewBox=\"0 0 520 420\" class=\"arch-diagram\" role=\"img\" aria-labelledby=\"archTitle archDesc\">\n            <title id=\"archTitle\">Sentrova architecture diagram</title>\n            <desc id=\"archDesc\">Applications and agents connect to the Sentrova gateway, which enforces policy, guardrails, PII redaction, and audit logging, then routes to model providers.</desc>\n            <defs>\n              <linearGradient id=\"gw\" x1=\"0\" y1=\"0\" x2=\"0\" y2=\"1\">\n                <stop offset=\"0\" stop-color=\"#15243f\"/>\n                <stop offset=\"1\" stop-color=\"#0e1830\"/>\n              </linearGradient>\n            </defs>\n\n            <!-- Apps column -->\n            <g class=\"diag-col\">\n              <text x=\"62\" y=\"28\" class=\"diag-head\" text-anchor=\"middle\">Apps &amp; Agents</text>\n              <g class=\"node\">\n                <rect x=\"12\" y=\"44\" width=\"100\" height=\"40\" rx=\"8\"/>\n                <text x=\"62\" y=\"69\" text-anchor=\"middle\">Copilot</text>\n              </g>\n              <g class=\"node\">\n                <rect x=\"12\" y=\"98\" width=\"100\" height=\"40\" rx=\"8\"/>\n                <text x=\"62\" y=\"123\" text-anchor=\"middle\">Agent fleet</text>\n              </g>\n              <g class=\"node\">\n                <rect x=\"12\" y=\"152\" width=\"100\" height=\"40\" rx=\"8\"/>\n                <text x=\"62\" y=\"177\" text-anchor=\"middle\">Internal apps</text>\n              </g>\n            </g>\n\n            <!-- flow lines apps -> gateway -->\n            <g class=\"flow\">\n              <path d=\"M112 64 H188\" />\n              <path d=\"M112 118 C150 118 150 150 188 150\" />\n              <path d=\"M112 172 C150 172 150 175 188 175\" />\n            </g>\n\n            <!-- Gateway -->\n            <g>\n              <rect x=\"190\" y=\"36\" width=\"140\" height=\"252\" rx=\"16\" fill=\"url(#gw)\" stroke=\"var(--gold)\" stroke-width=\"1.5\"/>\n              <g transform=\"translate(260,66)\">\n                <path fill=\"var(--gold)\" d=\"M0-18 -16-10v12c0 10 7.6 19.4 16 22 8.4-2.6 16-12 16-22v-12z\" transform=\"scale(0.8)\"/>\n                <path fill=\"var(--navy)\" d=\"m-3 4-4-4-2 2 6 6 9-9-2-2z\" transform=\"scale(0.8)\"/>\n              </g>\n              <text x=\"260\" y=\"78\" class=\"diag-head gold\" text-anchor=\"middle\">Sentrova Gateway</text>\n              <g class=\"pill\"><rect x=\"206\" y=\"96\" width=\"108\" height=\"30\" rx=\"6\"/><text x=\"260\" y=\"116\" text-anchor=\"middle\">Policy engine</text></g>\n              <g class=\"pill\"><rect x=\"206\" y=\"132\" width=\"108\" height=\"30\" rx=\"6\"/><text x=\"260\" y=\"152\" text-anchor=\"middle\">Guardrails</text></g>\n              <g class=\"pill\"><rect x=\"206\" y=\"168\" width=\"108\" height=\"30\" rx=\"6\"/><text x=\"260\" y=\"188\" text-anchor=\"middle\">PII redaction</text></g>\n              <g class=\"pill\"><rect x=\"206\" y=\"204\" width=\"108\" height=\"30\" rx=\"6\"/><text x=\"260\" y=\"224\" text-anchor=\"middle\">Audit log</text></g>\n              <g class=\"pill\"><rect x=\"206\" y=\"240\" width=\"108\" height=\"30\" rx=\"6\"/><text x=\"260\" y=\"260\" text-anchor=\"middle\">RBAC &amp; secrets</text></g>\n            </g>\n\n            <!-- flow lines gateway -> providers -->\n            <g class=\"flow\">\n              <path d=\"M330 110 C380 110 380 78 408 78\" />\n              <path d=\"M330 160 H408\" />\n              <path d=\"M330 210 C380 210 380 242 408 242\" />\n            </g>\n\n            <!-- Providers column -->\n            <g class=\"diag-col\">\n              <text x=\"460\" y=\"28\" class=\"diag-head\" text-anchor=\"middle\">Providers</text>\n              <g class=\"node alt\"><rect x=\"408\" y=\"58\" width=\"100\" height=\"40\" rx=\"8\"/><text x=\"458\" y=\"83\" text-anchor=\"middle\">Frontier API</text></g>\n              <g class=\"node alt\"><rect x=\"408\" y=\"140\" width=\"100\" height=\"40\" rx=\"8\"/><text x=\"458\" y=\"165\" text-anchor=\"middle\">Open models</text></g>\n              <g class=\"node alt\"><rect x=\"408\" y=\"222\" width=\"100\" height=\"40\" rx=\"8\"/><text x=\"458\" y=\"247\" text-anchor=\"middle\">Self-hosted</text></g>\n            </g>\n\n            <text x=\"260\" y=\"328\" class=\"diag-foot\" text-anchor=\"middle\">One endpoint. Every call governed, redacted &amp; logged.</text>\n          </svg>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ PROBLEM ============ -->\n    <section class=\"section\" id=\"problem\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">The problem</span>\n          <h2>Shadow AI is a liability waiting to happen</h2>\n          <p class=\"section-sub\">Teams are wiring agents to production data and live tools faster than anyone can govern them. Without a control plane, every agent is an ungoverned door into your enterprise.</p>\n        </div>\n        <div class=\"cards-3\">\n          <article class=\"card pain reveal\">\n            <div class=\"pain-num\">01</div>\n            <h3>Ungoverned spend</h3>\n            <p>Dozens of teams hold raw provider keys. There are no per-team caps, no rate limits, and no single bill \u2014 until a runaway agent burns five figures overnight.</p>\n          </article>\n          <article class=\"card pain reveal\">\n            <div class=\"pain-num\">02</div>\n            <h3>Data leakage</h3>\n            <p>Prompts carry customer PII, source code, and secrets straight to third-party models. Nothing inspects or redacts them, and no one can prove what left the building.</p>\n          </article>\n          <article class=\"card pain reveal\">\n            <div class=\"pain-num\">03</div>\n            <h3>No audit trail</h3>\n            <p>When legal, security, or an auditor asks \"what did the agents do?\", you have scattered logs at best. There is no defensible record of who called what, when, and why.</p>\n          </article>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ PLATFORM ============ -->\n    <section class=\"section section-alt\" id=\"platform\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">Platform</span>\n          <h2>One gateway. Every control your security team needs.</h2>\n          <p class=\"section-sub\">Sentrova is a single, OpenAI-compatible endpoint that wraps every model and agent call in enterprise-grade governance, security, and observability.</p>\n        </div>\n\n        <div class=\"feature-grid\">\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M4 7h10M4 7l3-3M4 7l3 3M20 17H10m10 0-3-3m3 3-3 3\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </span>\n            <h3>Unified gateway &amp; routing</h3>\n            <p>Point every app at one endpoint. Route across providers by cost, latency, or policy without touching application code.</p>\n          </article>\n\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M12 3 5 6v5c0 4 3 7.5 7 8.5 4-1 7-4.5 7-8.5V6z\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/><path d=\"M9 12h6M12 9v6\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\"/></svg>\n            </span>\n            <h3>Guardrails &amp; policy engine</h3>\n            <p>Author policy as code: who can call which models, with which tools, on what data. Enforced in-line on every request.</p>\n          </article>\n\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><rect x=\"4\" y=\"5\" width=\"16\" height=\"4\" rx=\"1\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\"/><path d=\"M7 13h6M7 17h10\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\"/><path d=\"M15 12.5h4v4h-4z\" fill=\"var(--gold)\" opacity=\".25\"/></svg>\n            </span>\n            <h3>PII redaction &amp; DLP</h3>\n            <p>Detect and redact PII, secrets, and regulated data before it reaches any provider. Tokenize, mask, or block by policy.</p>\n          </article>\n\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><circle cx=\"12\" cy=\"8\" r=\"3.2\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\"/><path d=\"M5 19c0-3.3 3.1-5.5 7-5.5s7 2.2 7 5.5\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\"/></svg>\n            </span>\n            <h3>RBAC &amp; secrets management</h3>\n            <p>Role-based access for teams and agents. Provider keys are vaulted in Sentrova \u2014 never handed to developers or apps.</p>\n          </article>\n\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M6 3h9l3 3v15H6z\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/><path d=\"M9 11h6M9 14h6M9 17h4\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\"/></svg>\n            </span>\n            <h3>Audit log &amp; evidence</h3>\n            <p>Every request and response captured as tamper-evident records. Export compliance evidence packs in one click.</p>\n          </article>\n\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M4 16V8m4 8V5m4 11V9m4 7v-5m4 5V7\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\"/></svg>\n            </span>\n            <h3>Cost controls &amp; rate limits</h3>\n            <p>Hard spend caps and rate limits per team, app, or agent. Real-time budgets stop runaway costs before they happen.</p>\n          </article>\n\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M12 3 5 6v5c0 4 3 7.5 7 8.5 4-1 7-4.5 7-8.5V6z\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linejoin=\"round\"/><path d=\"m9.5 11.5 1.8 1.8L15 9.5\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </span>\n            <h3>Prompt-injection defense</h3>\n            <p>Layered detectors flag prompt injection, jailbreaks, and unsafe tool calls. Quarantine, block, and alert in real time.</p>\n          </article>\n\n          <article class=\"card feature reveal\">\n            <span class=\"ficon\" aria-hidden=\"true\">\n              <svg viewBox=\"0 0 24 24\" width=\"24\" height=\"24\"><path d=\"M12 4v4m0 8v4M4 12h4m8 0h4\" stroke=\"var(--gold)\" stroke-width=\"1.8\" stroke-linecap=\"round\"/><circle cx=\"12\" cy=\"12\" r=\"3.2\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"1.8\"/></svg>\n            </span>\n            <h3>Multi-provider failover</h3>\n            <p>Automatic failover and load-balancing across providers and regions. Stay up when a single model API degrades.</p>\n          </article>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ HOW IT WORKS ============ -->\n    <section class=\"section\" id=\"how\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">How it works</span>\n          <h2>Drop in one endpoint. Govern everything behind it.</h2>\n          <p class=\"section-sub\">No rip-and-replace. Sentrova is OpenAI-compatible, so you change a base URL \u2014 not your codebase.</p>\n        </div>\n\n        <div class=\"how-grid\">\n          <ol class=\"how-steps reveal\">\n            <li>\n              <span class=\"step-n\">1</span>\n              <div>\n                <h3>Point your apps at one endpoint</h3>\n                <p>Swap your provider base URL for your Sentrova URL. Agents, copilots, and services now route through the gateway.</p>\n              </div>\n            </li>\n            <li>\n              <span class=\"step-n\">2</span>\n              <div>\n                <h3>Policies enforced in-line</h3>\n                <p>Every call is authenticated, checked against policy, redacted, and routed. Violations are blocked before reaching a provider.</p>\n              </div>\n            </li>\n            <li>\n              <span class=\"step-n\">3</span>\n              <div>\n                <h3>Everything logged &amp; exportable</h3>\n                <p>Each request and response is captured as audit evidence \u2014 searchable in the console, exportable for SOC 2 and ISO 27001.</p>\n              </div>\n            </li>\n          </ol>\n\n          <figure class=\"code-block reveal\" aria-label=\"Policy as code example\">\n            <figcaption><span class=\"filename\">policy.sentrova.yaml</span><span class=\"lang\">policy as code</span></figcaption>\n            <pre><code><span class=\"c-key\">policy</span>: <span class=\"c-str\">finance-agents</span>\n<span class=\"c-key\">match</span>:\n  <span class=\"c-key\">team</span>: <span class=\"c-str\">financial-services</span>\n<span class=\"c-key\">routing</span>:\n  <span class=\"c-key\">primary</span>: <span class=\"c-str\">frontier/large</span>\n  <span class=\"c-key\">fallback</span>: <span class=\"c-str\">self-hosted/secure</span>\n<span class=\"c-key\">redact</span>:\n  - <span class=\"c-str\">pii.email</span>\n  - <span class=\"c-str\">pii.ssn</span>\n  - <span class=\"c-str\">secret.api_key</span>\n<span class=\"c-key\">guardrails</span>:\n  <span class=\"c-key\">prompt_injection</span>: <span class=\"c-bool\">block</span>\n  <span class=\"c-key\">allowed_tools</span>: [<span class=\"c-str\">ledger.read</span>, <span class=\"c-str\">crm.read</span>]\n<span class=\"c-key\">limits</span>:\n  <span class=\"c-key\">monthly_usd</span>: <span class=\"c-num\">25000</span>\n  <span class=\"c-key\">rpm</span>: <span class=\"c-num\">600</span>\n<span class=\"c-key\">audit</span>:\n  <span class=\"c-key\">retain_days</span>: <span class=\"c-num\">2555</span>   <span class=\"c-cm\"># 7y retention</span>\n  <span class=\"c-key\">evidence</span>: <span class=\"c-bool\">true</span></code></pre>\n          </figure>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ COMPLIANCE ============ -->\n    <section class=\"section section-alt\" id=\"compliance\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">Compliance</span>\n          <h2>Audit-ready by design</h2>\n          <p class=\"section-sub\">Sentrova is built to the controls your auditors expect \u2014 and turns every agent call into defensible evidence.</p>\n        </div>\n\n        <div class=\"compliance-grid\">\n          <article class=\"card compliance reveal\">\n            <svg class=\"comp-badge\" viewBox=\"0 0 64 64\" aria-hidden=\"true\">\n              <circle cx=\"32\" cy=\"32\" r=\"30\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n              <path d=\"M32 12 16 19v11c0 9 7 16.5 16 19 9-2.5 16-10 16-19V19z\" fill=\"rgba(244,197,66,.12)\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n              <path d=\"m27 33 4 4 8-9\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"2.4\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/>\n            </svg>\n            <h3>SOC 2 Type II</h3>\n            <p>Continuous controls across security, availability, and confidentiality \u2014 with evidence Sentrova generates for you.</p>\n          </article>\n          <article class=\"card compliance reveal\">\n            <svg class=\"comp-badge\" viewBox=\"0 0 64 64\" aria-hidden=\"true\">\n              <circle cx=\"32\" cy=\"32\" r=\"30\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n              <path d=\"M20 22h24v6H20zM20 32h24v6H20zM20 42h16v0\" fill=\"rgba(244,197,66,.12)\" stroke=\"var(--gold)\" stroke-width=\"2\" stroke-linecap=\"round\"/>\n              <circle cx=\"44\" cy=\"44\" r=\"3\" fill=\"var(--gold)\"/>\n            </svg>\n            <h3>ISO 27001</h3>\n            <p>An information-security management system aligned to ISO 27001 controls, mapped directly to Sentrova's policy engine.</p>\n          </article>\n          <article class=\"card compliance reveal\">\n            <svg class=\"comp-badge\" viewBox=\"0 0 64 64\" aria-hidden=\"true\">\n              <circle cx=\"32\" cy=\"32\" r=\"30\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n              <circle cx=\"32\" cy=\"32\" r=\"14\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n              <g fill=\"var(--gold)\"><circle cx=\"32\" cy=\"20\" r=\"1.6\"/><circle cx=\"40.4\" cy=\"23.6\" r=\"1.6\"/><circle cx=\"44\" cy=\"32\" r=\"1.6\"/><circle cx=\"40.4\" cy=\"40.4\" r=\"1.6\"/><circle cx=\"32\" cy=\"44\" r=\"1.6\"/><circle cx=\"23.6\" cy=\"40.4\" r=\"1.6\"/><circle cx=\"20\" cy=\"32\" r=\"1.6\"/><circle cx=\"23.6\" cy=\"23.6\" r=\"1.6\"/></g>\n            </svg>\n            <h3>GDPR</h3>\n            <p>Data minimization, in-line redaction, regional routing, and full data-processing records for EU personal data.</p>\n          </article>\n          <article class=\"card compliance reveal\">\n            <svg class=\"comp-badge\" viewBox=\"0 0 64 64\" aria-hidden=\"true\">\n              <circle cx=\"32\" cy=\"32\" r=\"30\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n              <path d=\"M32 18v28M18 32h28\" stroke=\"var(--gold)\" stroke-width=\"4\" stroke-linecap=\"round\"/>\n              <circle cx=\"32\" cy=\"32\" r=\"11\" fill=\"none\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n            </svg>\n            <h3>HIPAA-ready</h3>\n            <p>PHI-aware redaction, BAA support, and self-hosted deployment patterns for protected health information.</p>\n          </article>\n        </div>\n\n        <div class=\"evidence-cta reveal\">\n          <div>\n            <h3>Export audit evidence in one click</h3>\n            <p>Generate a signed evidence pack \u2014 every relevant call, policy decision, and redaction event \u2014 scoped to a date range, team, or control. Hand it to auditors, not your engineers.</p>\n          </div>\n          <a class=\"btn btn-primary\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ USE CASES ============ -->\n    <section class=\"section\" id=\"use-cases\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">Use cases</span>\n          <h2>Built for the most regulated teams</h2>\n        </div>\n        <div class=\"cards-3\">\n          <article class=\"card usecase reveal\">\n            <h3>Financial services</h3>\n            <p>Keep MNPI and customer financial data out of third-party models. Enforce tool allowlists, regional routing, and 7-year audit retention for examiners.</p>\n          </article>\n          <article class=\"card usecase reveal\">\n            <h3>Healthcare</h3>\n            <p>Redact PHI in-line, deploy in your own VPC under a BAA, and prove every agent interaction met HIPAA handling rules.</p>\n          </article>\n          <article class=\"card usecase reveal\">\n            <h3>Public sector &amp; regulated SaaS</h3>\n            <p>Data residency, least-privilege access, and exportable evidence for FedRAMP-style reviews and enterprise security questionnaires.</p>\n          </article>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ STATS ============ -->\n    <section class=\"stats-band\" aria-label=\"Key outcomes\">\n      <div class=\"container stats-grid\">\n        <div class=\"stat reveal\">\n          <div class=\"stat-num\"><span data-count=\"1\">0</span></div>\n          <div class=\"stat-label\">endpoint for every model &amp; agent</div>\n        </div>\n        <div class=\"stat reveal\">\n          <div class=\"stat-num\"><span data-count=\"100\">0</span><span class=\"suffix\">%</span></div>\n          <div class=\"stat-label\">of calls logged as evidence</div>\n        </div>\n        <div class=\"stat reveal\">\n          <div class=\"stat-num\"><span data-count=\"0\">0</span></div>\n          <div class=\"stat-label\">PII records leaked to providers</div>\n        </div>\n        <div class=\"stat reveal\">\n          <div class=\"stat-num\">&lt;<span data-count=\"5\">0</span><span class=\"suffix\">ms</span></div>\n          <div class=\"stat-label\">added p50 gateway latency</div>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ PRICING ============ -->\n    <section class=\"section section-alt\" id=\"pricing\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">Pricing</span>\n          <h2>Start governed. Scale governed.</h2>\n          <p class=\"section-sub\">Every plan includes the full gateway, policy engine, and audit log. You pay for scale and support, not for security.</p>\n        </div>\n\n        <div class=\"pricing-grid\">\n          <article class=\"card price reveal\">\n            <h3>Team</h3>\n            <p class=\"price-desc\">For a single team putting first agents into production.</p>\n            <div class=\"price-amt\"><span class=\"cur\">$</span>499<span class=\"per\">/mo</span></div>\n            <ul class=\"price-feats\">\n              <li>Up to 10 seats</li>\n              <li>Unified gateway &amp; routing</li>\n              <li>Policy engine &amp; guardrails</li>\n              <li>PII redaction &amp; DLP</li>\n              <li>30-day audit retention</li>\n              <li>Email support</li>\n            </ul>\n            <a class=\"btn btn-outline\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n          </article>\n\n          <article class=\"card price featured reveal\">\n            <span class=\"price-tag\">Most popular</span>\n            <h3>Business</h3>\n            <p class=\"price-desc\">For platform teams governing AI across the org.</p>\n            <div class=\"price-amt\"><span class=\"cur\">$</span>2,500<span class=\"per\">/mo</span></div>\n            <ul class=\"price-feats\">\n              <li>Unlimited seats</li>\n              <li>Everything in Team, plus:</li>\n              <li>RBAC &amp; secrets vault</li>\n              <li>SSO / SCIM</li>\n              <li>1-year audit retention &amp; evidence packs</li>\n              <li>Prompt-injection defense</li>\n              <li>Priority support &amp; SLA</li>\n            </ul>\n            <a class=\"btn btn-primary\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n          </article>\n\n          <article class=\"card price reveal\">\n            <h3>Enterprise</h3>\n            <p class=\"price-desc\">For regulated enterprises with self-hosting needs.</p>\n            <div class=\"price-amt amt-contact\">Contact us</div>\n            <ul class=\"price-feats\">\n              <li>Self-hosted / VPC deployment</li>\n              <li>Everything in Business, plus:</li>\n              <li>Custom retention (up to 7y)</li>\n              <li>HIPAA BAA &amp; data residency</li>\n              <li>Dedicated environment &amp; SSO</li>\n              <li>Named security engineer</li>\n            </ul>\n            <a class=\"btn btn-outline\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n          </article>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ TESTIMONIALS ============ -->\n    <section class=\"section\" id=\"testimonials\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">What security leaders say</span>\n          <h2>The yes your board has been waiting for</h2>\n        </div>\n        <div class=\"tweet-wall\">\n          <figure class=\"tw\">\n            <div class=\"tw-head\">\n              <span class=\"tw-avatar\" aria-hidden=\"true\">PN</span>\n              <span class=\"tw-id\"><span class=\"tw-name\">Priya Nair<svg class=\"tw-verified\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M22.25 12c0-1.43-.88-2.67-2.19-3.34.46-1.39.2-2.9-.81-3.91s-2.52-1.27-3.91-.81c-.66-1.31-1.91-2.19-3.34-2.19s-2.67.88-3.33 2.19c-1.4-.46-2.91-.2-3.92.81s-1.26 2.52-.8 3.91c-1.31.67-2.2 1.91-2.2 3.34s.89 2.67 2.2 3.34c-.46 1.39-.21 2.9.8 3.91s2.52 1.26 3.91.81c.67 1.31 1.91 2.19 3.34 2.19s2.68-.88 3.34-2.19c1.39.45 2.9.2 3.91-.81s1.27-2.52.81-3.91c1.31-.67 2.19-1.91 2.19-3.34Zm-11.71 4.2L6.8 12.46l1.41-1.42 2.26 2.26 4.8-5.23 1.47 1.36-6.2 6.77Z\"/></svg></span><span class=\"tw-handle\">@priyasecops</span></span>\n              <svg class=\"tw-x\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231 5.45-6.231Zm-1.161 17.52h1.833L7.084 4.126H5.117L17.083 19.77Z\"/></svg>\n            </div>\n            <blockquote class=\"tw-body\">put <span class=\"tw-mention\">@sentrova</span> in front of every model call and for the first time i could answer &ldquo;what are the agents actually doing&rdquo; with <b>one export</b> instead of a 3-week scramble. board loved it.</blockquote>\n            <div class=\"tw-foot\" aria-hidden=\"true\"><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><path d=\"M21 11.5a8.38 8.38 0 0 1-8.5 8.5 8.5 8.5 0 0 1-3.8-.9L3 21l1.9-5.7A8.38 8.38 0 0 1 4 11.5 8.5 8.5 0 0 1 12.5 3 8.38 8.38 0 0 1 21 11.5Z\"/></svg>214</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M17 1l4 4-4 4\"/><path d=\"M3 11V9a4 4 0 0 1 4-4h14M7 23l-4-4 4-4\"/><path d=\"M21 13v2a4 4 0 0 1-4 4H3\"/></svg>1.1K</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 0 0-7.8 7.8l1 1L12 21l7.8-7.6 1-1a5.5 5.5 0 0 0 0-7.8Z\"/></svg>6.8K</span></div>\n          </figure>\n          <figure class=\"tw\">\n            <div class=\"tw-head\">\n              <span class=\"tw-avatar\" aria-hidden=\"true\">MF</span>\n              <span class=\"tw-id\"><span class=\"tw-name\">Marcus Feld</span><span class=\"tw-handle\">@mfeld_ciso</span></span>\n              <svg class=\"tw-x\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231 5.45-6.231Zm-1.161 17.52h1.833L7.084 4.126H5.117L17.083 19.77Z\"/></svg>\n            </div>\n            <blockquote class=\"tw-body\">PII redaction at the gateway took our healthcare AI program from &ldquo;legal won&rsquo;t approve&rdquo; to live in a quarter. the evidence packs paid for the platform at audit time.</blockquote>\n            <div class=\"tw-foot\" aria-hidden=\"true\"><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><path d=\"M21 11.5a8.38 8.38 0 0 1-8.5 8.5 8.5 8.5 0 0 1-3.8-.9L3 21l1.9-5.7A8.38 8.38 0 0 1 4 11.5 8.5 8.5 0 0 1 12.5 3 8.38 8.38 0 0 1 21 11.5Z\"/></svg>61</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M17 1l4 4-4 4\"/><path d=\"M3 11V9a4 4 0 0 1 4-4h14M7 23l-4-4 4-4\"/><path d=\"M21 13v2a4 4 0 0 1-4 4H3\"/></svg>340</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 0 0-7.8 7.8l1 1L12 21l7.8-7.6 1-1a5.5 5.5 0 0 0 0-7.8Z\"/></svg>2.9K</span></div>\n          </figure>\n          <figure class=\"tw\">\n            <div class=\"tw-head\">\n              <span class=\"tw-avatar\" aria-hidden=\"true\">DW</span>\n              <span class=\"tw-id\"><span class=\"tw-name\">Dana Whitaker<svg class=\"tw-verified\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M22.25 12c0-1.43-.88-2.67-2.19-3.34.46-1.39.2-2.9-.81-3.91s-2.52-1.27-3.91-.81c-.66-1.31-1.91-2.19-3.34-2.19s-2.67.88-3.33 2.19c-1.4-.46-2.91-.2-3.92.81s-1.26 2.52-.8 3.91c-1.31.67-2.2 1.91-2.2 3.34s.89 2.67 2.2 3.34c-.46 1.39-.21 2.9.8 3.91s2.52 1.26 3.91.81c.67 1.31 1.91 2.19 3.34 2.19s2.68-.88 3.34-2.19c1.39.45 2.9.2 3.91-.81s1.27-2.52.81-3.91c1.31-.67 2.19-1.91 2.19-3.34Zm-11.71 4.2L6.8 12.46l1.41-1.42 2.26 2.26 4.8-5.23 1.47 1.36-6.2 6.77Z\"/></svg></span><span class=\"tw-handle\">@dana_seceng</span></span>\n              <svg class=\"tw-x\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231 5.45-6.231Zm-1.161 17.52h1.833L7.084 4.126H5.117L17.083 19.77Z\"/></svg>\n            </div>\n            <blockquote class=\"tw-body\">per-team spend caps caught a misconfigured agent that would&rsquo;ve burned six figures overnight. then the audit trail closed <b>3 open SOC 2 findings</b>. wild.</blockquote>\n            <div class=\"tw-foot\" aria-hidden=\"true\"><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><path d=\"M21 11.5a8.38 8.38 0 0 1-8.5 8.5 8.5 8.5 0 0 1-3.8-.9L3 21l1.9-5.7A8.38 8.38 0 0 1 4 11.5 8.5 8.5 0 0 1 12.5 3 8.38 8.38 0 0 1 21 11.5Z\"/></svg>88</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M17 1l4 4-4 4\"/><path d=\"M3 11V9a4 4 0 0 1 4-4h14M7 23l-4-4 4-4\"/><path d=\"M21 13v2a4 4 0 0 1-4 4H3\"/></svg>402</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 0 0-7.8 7.8l1 1L12 21l7.8-7.6 1-1a5.5 5.5 0 0 0 0-7.8Z\"/></svg>3.4K</span></div>\n          </figure>\n          <figure class=\"tw\">\n            <div class=\"tw-head\">\n              <span class=\"tw-avatar\" aria-hidden=\"true\">SO</span>\n              <span class=\"tw-id\"><span class=\"tw-name\">Sam Oduya</span><span class=\"tw-handle\">@samoduya</span></span>\n              <svg class=\"tw-x\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231 5.45-6.231Zm-1.161 17.52h1.833L7.084 4.126H5.117L17.083 19.77Z\"/></svg>\n            </div>\n            <blockquote class=\"tw-body\">one endpoint, every model governed. we killed 12 raw provider keys floating around the org. security team finally said yes to agents.</blockquote>\n            <div class=\"tw-foot\" aria-hidden=\"true\"><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><path d=\"M21 11.5a8.38 8.38 0 0 1-8.5 8.5 8.5 8.5 0 0 1-3.8-.9L3 21l1.9-5.7A8.38 8.38 0 0 1 4 11.5 8.5 8.5 0 0 1 12.5 3 8.38 8.38 0 0 1 21 11.5Z\"/></svg>40</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M17 1l4 4-4 4\"/><path d=\"M3 11V9a4 4 0 0 1 4-4h14M7 23l-4-4 4-4\"/><path d=\"M21 13v2a4 4 0 0 1-4 4H3\"/></svg>190</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 0 0-7.8 7.8l1 1L12 21l7.8-7.6 1-1a5.5 5.5 0 0 0 0-7.8Z\"/></svg>1.7K</span></div>\n          </figure>\n          <figure class=\"tw\">\n            <div class=\"tw-head\">\n              <span class=\"tw-avatar\" aria-hidden=\"true\">LC</span>\n              <span class=\"tw-id\"><span class=\"tw-name\">Lena Cho<svg class=\"tw-verified\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M22.25 12c0-1.43-.88-2.67-2.19-3.34.46-1.39.2-2.9-.81-3.91s-2.52-1.27-3.91-.81c-.66-1.31-1.91-2.19-3.34-2.19s-2.67.88-3.33 2.19c-1.4-.46-2.91-.2-3.92.81s-1.26 2.52-.8 3.91c-1.31.67-2.2 1.91-2.2 3.34s.89 2.67 2.2 3.34c-.46 1.39-.21 2.9.8 3.91s2.52 1.26 3.91.81c.67 1.31 1.91 2.19 3.34 2.19s2.68-.88 3.34-2.19c1.39.45 2.9.2 3.91-.81s1.27-2.52.81-3.91c1.31-.67 2.19-1.91 2.19-3.34Zm-11.71 4.2L6.8 12.46l1.41-1.42 2.26 2.26 4.8-5.23 1.47 1.36-6.2 6.77Z\"/></svg></span><span class=\"tw-handle\">@lenabuildssec</span></span>\n              <svg class=\"tw-x\" viewBox=\"0 0 24 24\" fill=\"currentColor\" aria-hidden=\"true\"><path d=\"M18.244 2.25h3.308l-7.227 8.26 8.502 11.24H16.17l-5.214-6.817L4.99 21.75H1.68l7.73-8.835L1.254 2.25H8.08l4.713 6.231 5.45-6.231Zm-1.161 17.52h1.833L7.084 4.126H5.117L17.083 19.77Z\"/></svg>\n            </div>\n            <blockquote class=\"tw-body\">prompt-injection guardrails + full logging out of the box. <span class=\"tw-mention\">@sentrova</span> is the layer i kept trying to build internally and never had time to.</blockquote>\n            <div class=\"tw-foot\" aria-hidden=\"true\"><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><path d=\"M21 11.5a8.38 8.38 0 0 1-8.5 8.5 8.5 8.5 0 0 1-3.8-.9L3 21l1.9-5.7A8.38 8.38 0 0 1 4 11.5 8.5 8.5 0 0 1 12.5 3 8.38 8.38 0 0 1 21 11.5Z\"/></svg>73</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M17 1l4 4-4 4\"/><path d=\"M3 11V9a4 4 0 0 1 4-4h14M7 23l-4-4 4-4\"/><path d=\"M21 13v2a4 4 0 0 1-4 4H3\"/></svg>512</span><span><svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M20.8 4.6a5.5 5.5 0 0 0-7.8 0L12 5.6l-1-1a5.5 5.5 0 0 0-7.8 7.8l1 1L12 21l7.8-7.6 1-1a5.5 5.5 0 0 0 0-7.8Z\"/></svg>4.1K</span></div>\n          </figure>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ FOUNDER ============ -->\n    <section class=\"section section-alt\" id=\"about\">\n      <div class=\"container founder-grid\">\n        <div class=\"founder-avatar reveal\" aria-hidden=\"true\">\n          <svg viewBox=\"0 0 160 160\" width=\"160\" height=\"160\">\n            <defs>\n              <linearGradient id=\"mono\" x1=\"0\" y1=\"0\" x2=\"1\" y2=\"1\">\n                <stop offset=\"0\" stop-color=\"#1b2c4d\"/>\n                <stop offset=\"1\" stop-color=\"#0e1830\"/>\n              </linearGradient>\n            </defs>\n            <circle cx=\"80\" cy=\"80\" r=\"78\" fill=\"url(#mono)\" stroke=\"var(--gold)\" stroke-width=\"2\"/>\n            <text x=\"80\" y=\"102\" text-anchor=\"middle\" font-family=\"Sora, sans-serif\" font-size=\"64\" font-weight=\"700\" fill=\"var(--gold)\">S</text>\n          </svg>\n        </div>\n        <div class=\"founder-copy reveal\">\n          <span class=\"kicker\">Founder</span>\n          <h2>Swathi \u2014 Founder &amp; CEO</h2>\n          <p>Swathi has spent her career in enterprise-AI adoption and the security and compliance work that gates it \u2014 deep on AI gateways and LiteLLM-style routing, SOC 2 Type II, and ISO 27001.</p>\n          <p class=\"founder-belief\">\"Enterprises won't deploy agents at scale until there's a security and governance layer they can trust. Sentrova is that layer.\"</p>\n          <p class=\"founder-link\"><a href=\"https://www.linkedin.com/in/ihtaws/\" target=\"_blank\" rel=\"noopener\">Connect on LinkedIn &rarr;</a></p>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ FAQ ============ -->\n    <section class=\"section\" id=\"faq\">\n      <div class=\"container\">\n        <div class=\"section-head reveal\">\n          <span class=\"kicker\">FAQ</span>\n          <h2>Security &amp; compliance questions</h2>\n        </div>\n\n        <div class=\"faq-list reveal\">\n          <div class=\"faq-item\">\n            <button class=\"faq-q\" aria-expanded=\"false\">\n              <span>How does Sentrova sit in front of my models and agents?</span>\n              <svg class=\"faq-ico\" viewBox=\"0 0 24 24\" width=\"22\" height=\"22\" aria-hidden=\"true\"><path d=\"M6 9l6 6 6-6\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </button>\n            <div class=\"faq-a\"><p>Sentrova is an OpenAI-compatible gateway. You point your apps and agents at a single Sentrova endpoint instead of each provider. Sentrova authenticates the caller, applies policy, redacts sensitive data, routes to the right model, and logs the full request and response for audit.</p></div>\n          </div>\n\n          <div class=\"faq-item\">\n            <button class=\"faq-q\" aria-expanded=\"false\">\n              <span>Is Sentrova SOC 2 Type II and ISO 27001 compliant?</span>\n              <svg class=\"faq-ico\" viewBox=\"0 0 24 24\" width=\"22\" height=\"22\" aria-hidden=\"true\"><path d=\"M6 9l6 6 6-6\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </button>\n            <div class=\"faq-a\"><p>Sentrova is built to SOC 2 Type II and ISO 27001 controls and is designed to accelerate your own audits. Every model and agent call is logged with tamper-evident records you can export as compliance evidence. We also support GDPR data handling and HIPAA-ready deployment patterns.</p></div>\n          </div>\n\n          <div class=\"faq-item\">\n            <button class=\"faq-q\" aria-expanded=\"false\">\n              <span>Can I run Sentrova self-hosted or in my own VPC?</span>\n              <svg class=\"faq-ico\" viewBox=\"0 0 24 24\" width=\"22\" height=\"22\" aria-hidden=\"true\"><path d=\"M6 9l6 6 6-6\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </button>\n            <div class=\"faq-a\"><p>Yes. Sentrova runs as a managed cloud service or fully self-hosted inside your own VPC or on-prem environment, so prompts, completions, and keys never leave your boundary. Both deployment modes share the same policy engine and audit pipeline.</p></div>\n          </div>\n\n          <div class=\"faq-item\">\n            <button class=\"faq-q\" aria-expanded=\"false\">\n              <span>How does PII redaction and data-loss prevention work?</span>\n              <svg class=\"faq-ico\" viewBox=\"0 0 24 24\" width=\"22\" height=\"22\" aria-hidden=\"true\"><path d=\"M6 9l6 6 6-6\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </button>\n            <div class=\"faq-a\"><p>Sentrova inspects every prompt and response in-line. Configurable detectors catch PII, secrets, and regulated data, then redact, tokenize, or block based on your policy \u2014 before the data ever reaches a model provider. All actions are logged for review.</p></div>\n          </div>\n\n          <div class=\"faq-item\">\n            <button class=\"faq-q\" aria-expanded=\"false\">\n              <span>Does Sentrova defend against prompt injection and jailbreaks?</span>\n              <svg class=\"faq-ico\" viewBox=\"0 0 24 24\" width=\"22\" height=\"22\" aria-hidden=\"true\"><path d=\"M6 9l6 6 6-6\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </button>\n            <div class=\"faq-a\"><p>Yes. Sentrova's guardrail engine runs layered detectors for prompt injection, jailbreak attempts, and unsafe tool calls, and lets you enforce allowlists for tools, domains, and data sources. Suspicious requests are blocked or quarantined and surfaced to your security team.</p></div>\n          </div>\n\n          <div class=\"faq-item\">\n            <button class=\"faq-q\" aria-expanded=\"false\">\n              <span>Which model providers does Sentrova support?</span>\n              <svg class=\"faq-ico\" viewBox=\"0 0 24 24\" width=\"22\" height=\"22\" aria-hidden=\"true\"><path d=\"M6 9l6 6 6-6\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"/></svg>\n            </button>\n            <div class=\"faq-a\"><p>Sentrova routes across major providers and self-hosted open models through one unified, OpenAI-compatible interface, with automatic failover and per-team spend caps. Adding or swapping a provider is a config change \u2014 your applications never change code.</p></div>\n          </div>\n        </div>\n      </div>\n    </section>\n\n    <!-- ============ FINAL CTA ============ -->\n    <section class=\"cta-band\" id=\"contact\">\n      <div class=\"container cta-inner reveal\">\n        <h2>Bring your agents under control</h2>\n        <p>Put Sentrova in front of every model and agent \u2014 and give your security team the gateway, guardrails, and audit trail they've been asking for.</p>\n        <div class=\"cta-actions\">\n          <a class=\"btn btn-primary btn-lg\" href=\"mailto:operations@sentrova.app?subject=Contact%20Sentrova\">Contact us</a>\n        </div>\n        <p class=\"cta-fine\">SOC 2 Type II &middot; ISO 27001 &middot; GDPR &middot; HIPAA-ready</p>\n      </div>\n    </section>\n  </main>\n\n  <!-- ============ FOOTER ============ -->\n  <footer class=\"site-footer\" id=\"docs\">\n    <div class=\"container footer-grid\">\n      <div class=\"footer-brand\">\n        <a class=\"brand\" href=\"#top\" aria-label=\"Sentrova home\">\n          <svg class=\"brand-mark\" width=\"28\" height=\"28\" viewBox=\"0 0 24 24\" aria-hidden=\"true\">\n            <path fill=\"var(--gold)\" d=\"M12 1 3 5v6c0 5 3.8 9.7 9 11 5.2-1.3 9-6 9-11V5z\"/>\n            <path fill=\"var(--navy)\" d=\"m10.6 14.2-2.2-2.2-1.4 1.4 3.6 3.6 6-6-1.4-1.4z\"/>\n          </svg>\n          <span class=\"brand-name\">Sentrova</span>\n        </a>\n        <p class=\"footer-tag\">The control plane for enterprise AI agents.</p>\n        <p class=\"ef-line\"><span class=\"ef-badge\"><span class=\"efbox\">EF</span> Backed by Entrepreneurs First</span></p>\n        <div class=\"footer-col footer-contact\">\n          <a href=\"mailto:operations@sentrova.app\">\n            <svg viewBox=\"0 0 24 24\" width=\"18\" height=\"18\" aria-hidden=\"true\" style=\"vertical-align:-3px;margin-right:8px\"><path fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linejoin=\"round\" d=\"M3 6h18v12H3z\"/><path fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"m3 7 9 6 9-6\"/></svg>operations@sentrova.app\n          </a>\n        </div>\n      </div>\n\n      <nav class=\"footer-col\" aria-label=\"Platform\">\n        <h3>Platform</h3>\n        <a href=\"#platform\">Gateway &amp; routing</a>\n        <a href=\"#platform\">Guardrails &amp; policy</a>\n        <a href=\"#platform\">PII redaction</a>\n        <a href=\"#platform\">Audit &amp; evidence</a>\n        <a href=\"#pricing\">Pricing</a>\n      </nav>\n\n      <nav class=\"footer-col\" aria-label=\"Company\">\n        <h3>Company</h3>\n        <a href=\"#about\">About</a>\n        <a href=\"#testimonials\">Customers</a>\n        <a href=\"mailto:operations@sentrova.app\">Careers</a>\n        <a href=\"mailto:operations@sentrova.app\">Press</a>\n        <a href=\"#contact\">Contact</a>\n      </nav>\n\n      <nav class=\"footer-col\" aria-label=\"Resources\">\n        <h3>Resources</h3>\n        <a href=\"#how\">How it works</a>\n        <a href=\"#compliance\">Compliance center</a>\n        <a href=\"#faq\">FAQ</a>\n        <a href=\"#compliance\">Trust &amp; security</a>\n      </nav>\n\n      <nav class=\"footer-col\" aria-label=\"Legal\">\n        <h3>Legal</h3>\n        <a href=\"#\">Privacy policy</a>\n        <a href=\"#\">Terms of service</a>\n        <a href=\"#\">Data processing (DPA)</a>\n        <a href=\"#\">Subprocessors</a>\n        <a href=\"#\">Responsible disclosure</a>\n      </nav>\n    </div>\n    <div class=\"container footer-bottom\">\n      <p>&copy; <span id=\"year\">2026</span> Sentrova. All rights reserved. Founded by Swathi &middot; sentrova.app</p>\n    </div>\n  </footer>";

